import{_ as e,o as a,c as r,ae as o}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"Dashboard Custom Exports","description":"","frontmatter":{"title":"Dashboard Custom Exports","slug":"dashboard-custom-exports"},"headers":[],"relativePath":"marketer-hub/dashboard-custom-exports.md","filePath":"marketer-hub/dashboard-custom-exports.md"}'),s={name:"marketer-hub/dashboard-custom-exports.md"};function i(n,t,d,l,h,c){return a(),r("div",null,[...t[0]||(t[0]=[o('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Branch data is valuable when it comes to truly understanding your campaign performance. One way to understand Branch data at a granular level is through Branch Custom Exports. Users with the correct permission can access Custom Exports via the Branch Dashboard (this guide) or via the <a href="./custom-exports-api.html">Custom Exports API</a>.</p><p>Custom Exports through the Branch Dashboard will be outputted in CSV or JSON.</p><h2 id="limitations" tabindex="-1">Limitations <a class="header-anchor" href="#limitations" aria-label="Permalink to &quot;Limitations&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p><strong>Apple requires users to opt in to sharing their device data through</strong> <a href="https://developer.apple.com/app-store/user-privacy-and-data-use/" target="_blank" rel="noreferrer"><strong>Apple&#39;s AppTrackingTransparency framework</strong></a><strong>. When an install is attributed to paid ads, a 2nd install event will fire post user opt-in.</strong></p><p>Opt-ins will affect your final install count. Our recommendation is to use a different identifier (ex. IDFV) to de-dupe install events on your internal systems.</p><p>For additional information on changes post iOS 14.5, visit our <a href="./ios-14-faqs.html">FAQ Pages</a>.</p></div><table tabindex="0"><thead><tr><th>Limitation</th><th>Details</th></tr></thead><tbody><tr><td>Max number of days that can be queried at a time</td><td>60 days</td></tr><tr><td>Max number of records per export</td><td>2 million</td></tr><tr><td>Max lookback</td><td>180 Days</td></tr><tr><td>Rate Limits</td><td>- 10 requests per minute - 25 requests per hour</td></tr><tr><td>Test Environment Custom Export</td><td>Not supported</td></tr><tr><td>Identical Requests</td><td>Export requests made within 60 minutes will be cached to avoid the case of hundreds or thousands of requests being made for the exact same data set within seconds or minutes of each other. After 60 minutes, your request will kick off a new job to retrieve data.</td></tr></tbody></table><p>If more records are required, please make multiple requests with smaller intervals to pull the necessary data in &quot;batches&quot;.</p><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><p>In order to access Custom Exports, you need to have completed the following:</p><ol><li><p>Created a <a href="https://dashboard.branch.io/" target="_blank" rel="noreferrer">Branch Dashboard</a>.</p></li><li><p>Enabled Data Feeds for your Branch account.</p><ul><li>Contact your Branch account manager or visit <a href="https://branch.io/pricing" target="_blank" rel="noreferrer">https://branch.io/pricing</a></li></ul></li><li><p>Implemented the Branch SDK into your mobile app (<a href="./ios-sdk-overview.html">iOS</a> | <a href="./android-sdk-overview.html">Android</a>)</p><ul><li><a href="./track-branch-events.html">Track events</a></li></ul></li><li><p>Have <a href="./add-manage-users-roles-permissions-access.html"><strong>Sensitive Data and Export access</strong></a>.</p></li></ol><h3 id="agency-access" tabindex="-1">Agency Access <a class="header-anchor" href="#agency-access" aria-label="Permalink to &quot;Agency Access&quot;">​</a></h3><p>If you work with an agency that runs your advertising campaigns and you want to give them access to export the subsequent data, you can provide them with access to the Custom Exports</p><p>To provide an agency team member with access to the Custom Export API:</p><ol><li><p>In the left-hand navigation, under <strong>Configure</strong>, click on <strong>Account Settings</strong>.</p></li><li><p>On the <strong>Account Settings</strong> page, click on the <strong>Agencies</strong> tab.</p></li><li><p>Expand the agency in question, find the agency team member you want to give access to, hover on the button in the <strong>Actions</strong> column and click <strong>Edit</strong>.</p></li><li><p>In the <strong>Edit Agency Team Member</strong> modal:</p><ul><li>Under <strong>Access Level</strong>, check the <strong>Export</strong> box.</li><li>Under <strong>Permissions</strong>, check the <strong>Sensitive Data</strong> box.</li></ul></li><li><p>Optional: add data filters</p><ul><li>Under <strong>Data Filters</strong>, toggle any necessary data filters on/blue. Exported data will be filtered accordingly.</li></ul></li><li><p>Click <strong>Save</strong>.</p></li></ol><h2 id="pre-configured-exports" tabindex="-1">Pre-Configured Exports <a class="header-anchor" href="#pre-configured-exports" aria-label="Permalink to &quot;Pre-Configured Exports&quot;">​</a></h2><p>Use pre-configured exports to quickly access specific exports configured by Branch or created by other users who have access to your Branch Dashboard.</p><p>After logging in to Branch Dashboard, in the left-hand navigation, under the <strong>Exports</strong> section, click <a href="https://dashboard.branch.io/custom-exports" target="_blank" rel="noreferrer"><strong>Custom Exports</strong></a>. Pre-configured exports should be accessible through the dropdown, and selecting one will overwrite anything set in the <strong>Create Custom Exports</strong> section with pre-configured settings (topic, dimensions, filters).</p><h3 id="default-pre-configured-exports" tabindex="-1">Default Pre-Configured Exports <a class="header-anchor" href="#default-pre-configured-exports" aria-label="Permalink to &quot;Default Pre-Configured Exports&quot;">​</a></h3><p>Branch supplies a set a pre-configured exports that will make getting started easier:</p><table tabindex="0"><thead><tr><th>Pre-Configured Export</th><th>Description</th></tr></thead><tbody><tr><td>Paid Attributed Installs</td><td>Export attributed installs for paid ads campaigns.</td></tr><tr><td>SAN Attributed Installs</td><td>Export attributed installs for ads campaigns from self-attributing networks (Facebook, Google Adwords, Google Marketing Platform, Twitter, Snap, Apple).</td></tr><tr><td>SAN Attributed Purchase</td><td>Export attributed commerce events for ads campaigns from self-attributing networks (Facebook, Google Adwords, Google Marketing Platform, Twitter, Snap, Apple).</td></tr><tr><td>SAN Touch</td><td>Export self-attributing network touches used for measuring multi-touch attribution.</td></tr><tr><td>Non-Paid Channels Installs</td><td>Export attributed installs for non-paid ads channels.</td></tr><tr><td>Acquisition Cohort Purchase</td><td>Export attributed purchase events.</td></tr></tbody></table><h2 id="create-custom-exports" tabindex="-1">Create Custom Exports <a class="header-anchor" href="#create-custom-exports" aria-label="Permalink to &quot;Create Custom Exports&quot;">​</a></h2><p>After logging in to Branch Dashboard, in the left-hand navigation, under the <strong>Exports</strong> section, click <a href="https://dashboard.branch.io/custom-exports" target="_blank" rel="noreferrer"><strong>Custom Exports</strong></a>.</p><p><em>[Image: 1145]</em></p><h3 id="_1-set-dates-times-and-timezone" tabindex="-1">1. Set Dates, Times, and Timezone <a class="header-anchor" href="#_1-set-dates-times-and-timezone" aria-label="Permalink to &quot;1. Set Dates, Times, and Timezone&quot;">​</a></h3><p>When setting your date, time, and timezone, be sure that your export is within the <a href="./dashboard-custom-exports.html#limitations">limitations</a>.</p><h3 id="_2-set-topic" tabindex="-1">2. Set Topic <a class="header-anchor" href="#_2-set-topic" aria-label="Permalink to &quot;2. Set Topic&quot;">​</a></h3><p>The topic you select should be based on what you are looking to export. For most cases, you will want to select the topic that matches your event name. See below to outline which topic to select based on the event:</p><h4 id="topic-event-mappings" tabindex="-1">Topic Event Mappings: <a class="header-anchor" href="#topic-event-mappings" aria-label="Permalink to &quot;Topic Event Mappings:&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Event Type</th><th>Event Names</th></tr></thead><tbody><tr><td>Commerce Events</td><td>- Add To Cart - Add To Wishlist - View Cart - Initiate Purchase - Add Payment Info - Click Ad - Purchase - Reserve - Spend Credits - View Ad</td></tr><tr><td>Content Events</td><td>- Search - View Item - View Items - Rate - Share - Initiate Stream - Complete Stream</td></tr><tr><td>User Lifecycle Events</td><td>- Complete Registration - Complete Tutorial - Achieve Level - Unlock Achievement - Invite - Login - Start Trial - Subscribe - Opt In - Opt Out</td></tr><tr><td>Custom Events</td><td>All other event names</td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">Fraud</p><p>You can also set the Topic to any of the <strong>Blocked</strong> events to filter for any fraudulent events with device IDs.</p></div><h3 id="_3-select-columns" tabindex="-1">3. Select Columns <a class="header-anchor" href="#_3-select-columns" aria-label="Permalink to &quot;3. Select Columns&quot;">​</a></h3><p>The columns you select are dependent on what you are looking to understand out of your export.</p><h3 id="_4-configure-filters" tabindex="-1">4. Configure Filters <a class="header-anchor" href="#_4-configure-filters" aria-label="Permalink to &quot;4. Configure Filters&quot;">​</a></h3><p>You can add filters to get even more granular with what you are exporting. Filters help you specify the values for the columns you are looking to export.</p><h2 id="example-custom-exports" tabindex="-1">Example Custom Exports <a class="header-anchor" href="#example-custom-exports" aria-label="Permalink to &quot;Example Custom Exports&quot;">​</a></h2><p>There are many purposes for initiating a Custom Export depending on the type of data you are looking to analyze. Below are a few examples:</p><h3 id="android-ios-installs-with-device-ids" tabindex="-1">Android &amp; iOS Installs with Device IDs <a class="header-anchor" href="#android-ios-installs-with-device-ids" aria-label="Permalink to &quot;Android &amp; iOS Installs with Device IDs&quot;">​</a></h3><p>.png)</p><table tabindex="0"><thead><tr><th>Configuration</th><th>Details</th></tr></thead><tbody><tr><td>Topic</td><td>Installs</td></tr><tr><td>Columns</td><td>- Attributed - OS - AAID - Android ID - IDFA - IDFV - Developer Identity</td></tr><tr><td>Filters</td><td><code>OS</code> in <code>ANDROID, IOS</code></td></tr></tbody></table><h3 id="purchase-event-data" tabindex="-1">Purchase Event Data <a class="header-anchor" href="#purchase-event-data" aria-label="Permalink to &quot;Purchase Event Data&quot;">​</a></h3><p>.png)</p><table tabindex="0"><thead><tr><th>Configuration</th><th>Details</th></tr></thead><tbody><tr><td>Topic</td><td>Commerce Events</td></tr><tr><td>Columns</td><td>- Attributed - Name - Campaign - Content Items - Coupon - Customer Event Alias - Custom Data - Currency - Developer Identity - Event Timestamp - OS - Revenue - Revenue in USD - Shipping - Tax - Transaction ID - Timestamp</td></tr><tr><td>Filters</td><td><code>Name</code> equals <code>PURCHASE</code></td></tr></tbody></table>',42)])])}const m=e(s,[["render",i]]);export{u as __pageData,m as default};
